  /* ---------- Format ---------- */
  function eur(v){ return v==null?"\u2014":Math.round(v).toLocaleString("de-DE")+" \u20AC"; }
  function eur2(v){ return v==null?"\u2014":v.toLocaleString("de-DE",{minimumFractionDigits:2,maximumFractionDigits:2})+" \u20AC"; }
  function num(v,d){ return v==null?"\u2014":v.toLocaleString("de-DE",{minimumFractionDigits:d||0,maximumFractionDigits:d||0}); }
  function pct(v,d){ return v==null?"\u2014":v.toLocaleString("de-DE",{minimumFractionDigits:d||1,maximumFractionDigits:d||1})+" %"; }
  function signPct(v){ if(v==null) return "\u2014"; var s=v>=0?"+":"\u2212"; return s+Math.abs(v).toLocaleString("de-DE",{maximumFractionDigits:0})+" %"; }
  function esc(s){ return String(s==null?"":s).replace(/[&<>"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c];}); }

  /* ---------- Rollen-Erkennung aus Metadaten-Namen ---------- */
  function low(s){ return String(s||"").toLowerCase(); }
  function classifyDim(t){ t=low(t);
    if(/transaktion|transaction|beleg.?nr|bon.?nr|receipt/.test(t)) return "txid";
    if(/filial|\bstore\b|\bshop\b|\bmarkt\b|outlet/.test(t)) return "fil";
    if(/region|bezirk|gebiet/.test(t)) return "reg";
    if(/standorttyp|lage|innenstadt|gewerbe|stadtrand/.test(t)) return "st";
    if(/kunde|customer|b2b|b2c/.test(t)) return "kt";
    if(/waren|kategorie|sortiment|produktgrupp|category|abteilung/.test(t)) return "wk";
    if(/zahl|payment|bezahl/.test(t)) return "za";
    if(/wochentag|weekday/.test(t)) return "wd";
    if(/position|rolle|funktion|\brole\b/.test(t)) return "pos";
    if(/beschäft|beschaeft|vollzeit|teilzeit|employment|vertragsart/.test(t)) return "besch";
    if(/mitarbeiter|employee|verkäufer|verkaeufer|personal|\bma[_ ]?id\b/.test(t)) return "mit";
    if(/retour|\breturn\b|storno/.test(t)) return "retdim";
    if(/datum|\bdate\b/.test(t)) return "dat";
    return null;
  }
  function classifyMeas(t){ t=low(t);
    if(/artikel|menge|stück|stueck|quantity|\bqty\b|\bstk\b/.test(t)) return "art";
    if(/(umsatz|sales|revenue|erlös|erloes).*(netto|net)|(netto|net).*(umsatz|sales|revenue)/.test(t)) return "u";
    if(/(umsatz|sales|revenue).*(brutto|gross)|(brutto|gross).*(umsatz|sales|revenue)/.test(t)) return "br";
    if(/rabatt|discount|nachlass/.test(t)) return "rb";
    if(/bon|beleg|transak|receipt|kassen|counter|\bcount\b|frequenz|kundenzahl|anzahl/.test(t)) return "bons";
    if(/fläche|flaeche|\bqm\b|sqm|m²|\barea\b|verkaufsfl/.test(t)) return "fl";
    if(/umsatz|sales|revenue|erlös|erloes/.test(t)) return "u";
    return null;
  }

  /* ---------- Dimensions-Labels fuer UI ---------- */
  var DIMLBL = { wk:"Warenkategorie", kt:"Kundentyp", pos:"Position", mit:"Mitarbeiter",
    za:"Zahlungsart", wd:"Wochentag", reg:"Region", st:"Standorttyp", besch:"Beschäftigung" };
  var MEASLBL = { u:"Umsatz Netto", br:"Umsatz Brutto", rb:"Rabatt", art:"Anzahl Artikel",
    bons:"Anzahl Bons", fl:"Verkaufsfläche" };

  /* ---------- Treiber-Aggregation ---------- */
  function agg(rows){ var a={u:0,br:0,rb:0,art:0,bons:0,ret:0,tx:0};
    for(var i=0;i<rows.length;i++){ var r=rows[i];
      a.u+=r.u||0; a.br+=r.br||0; a.rb+=r.rb||0; a.art+=r.art||0; a.bons+=r.bons||0; a.ret+=r.ret||0; a.tx+=r.tx||0; }
    return a; }
  function drivers(rows, flaeche, cap){
    var a=agg(rows), hasBons=cap.bons, hasArt=cap.art, hasBr=cap.br, hasFl=flaeche!=null;
    return {
      umsatz:a.u,
      bons: hasBons? a.bons : null,
      artikel: hasArt? a.art : null,
      bonwert: (hasBons&&a.bons)? a.u/a.bons : null,
      artbon: (hasBons&&hasArt&&a.bons)? a.art/a.bons : null,
      stueck: (hasArt&&a.art)? a.u/a.art : null,
      rabq: hasBr&&a.br? a.rb/a.br*100 : null,
      retq: cap.retq&&a.tx? a.ret/a.tx*100 : null,
      upqm: hasFl&&flaeche? a.u/flaeche : null,
      _raw:a
    };
  }
  var DRV = {
    bonwert:{label:"Bonwert",better:1,fmt:eur2},
    artbon:{label:"Artikel je Bon",better:1,fmt:function(v){return num(v,1);}},
    stueck:{label:"\u00D8 St\u00FCckpreis",better:1,fmt:eur2},
    bons:{label:"Anzahl Bons",better:1,fmt:function(v){return num(v,0);}},
    rabq:{label:"Rabattquote",better:-1,fmt:function(v){return pct(v,1);}},
    retq:{label:"Retourenquote",better:-1,fmt:function(v){return pct(v,1);}},
    upqm:{label:"Umsatz / qm",better:1,fmt:eur2}
  };
  function status(dev,better,thr){ if(dev==null) return "neutral"; var d=dev*(better||1);
    if(d>thr) return "pos"; if(d<-thr) return "neg"; return "neutral"; }

